ALTER TABLE assessment_form_templates ADD COLUMN IF NOT EXISTS mcid_value numeric, ADD COLUMN IF NOT EXISTS max_possible_score numeric, ADD COLUMN IF NOT EXISTS severity_thresholds jsonb; ALTER TABLE assessment_form_responses ADD COLUMN IF NOT EXISTS total_score numeric; UPDATE assessment_form_responses SET total_score = (responses->>'total_score')::numeric WHERE total_score IS NULL AND responses->>'total_score' IS NOT NULL;;
